    ranked_child_nodes = sorted(child_nodes_with_capacity.items(), key=lambda x: x[1], reverse=True)
    return_object = {
        'type': 'list',
        'data': ranked_child_nodes,
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }
    return return_object

